    10→import { getAllSeries, getAllBooks, getSeriesData } from "@/lib/markdown";
    11→import { resolveLocale } from "@/lib/i18n";
    12→import "./globals.css";
    13→
    14→const inter = localFont({
    15→  src: [
    16→    {
    17→      path: "../fonts/Inter-Regular.woff2",
    18→      weight: "400",
    19→      style: "normal",
    20→    },
    21→    {
    22→      path: "../fonts/Inter-Bold.woff2",
    23→      weight: "700",
    24→      style: "normal",
    25→    },
    26→  ],
    27→  variable: "--font-inter",
    28→});
    29→
    30→const baskerville = localFont({
    31→  src: [
    32→    {
    33→      path: "../fonts/LibreBaskerville-Regular.ttf",
    34→      weight: "400",
    35→      style: "normal",
    36→    },
    37→    {
    38→      path: "../fonts/LibreBaskerville-Bold.ttf",
    39→      weight: "700",
    40→      style: "normal",
    41→    },
    42→    {
    43→      path: "../fonts/LibreBaskerville-Italic.ttf",
    44→      weight: "400",
    45→      style: "italic",
    46→    },
    47→  ],
    48→  variable: "--font-baskerville",
    49→});
    50→
    51→const siteTwitterHandle = (() => {
    52→  const url = siteConfig.social?.twitter ?? '';
    53→  const m = url.match(/(?:twitter\.com|x\.com)\/([^/?#]+)/);
    54→  return m ? `@${m[1]}` : undefined;
    55→})();
    56→
    57→// Build icon metadata with explicit MIME type so browsers correctly handle
    58→// all formats. Without this, .ico files served via the metadata API lack
    59→// type="image/x-icon" and may be ignored in favour of app/favicon.ico.
    60→const faviconSrc = siteConfig.logo?.favicon || "/icon.svg";
    61→const ext = faviconSrc.split('.').pop()?.toLowerCase();
    62→const faviconMeta =
    63→  ext === 'ico' ? [{ url: faviconSrc, type: 'image/x-icon', sizes: 'any' }] :
    64→  ext === 'png' ? [{ url: faviconSrc, type: 'image/png' }] :
    65→  ext === 'svg' ? [{ url: faviconSrc, type: 'image/svg+xml' }] :
    66→  faviconSrc;
    67→
    68→const feedAlternates = (() => {
    69→  const { format } = siteConfig.feed;
    70→  const types: Record<string, string> = {};
    71→  if (format === 'rss' || format === 'both') types['application/rss+xml'] = '/feed.xml';
    72→  if (format === 'atom' || format === 'both') types['application/atom+xml'] = '/feed.atom';
    73→  return Object.keys(types).length > 0 ? { types } : undefined;
    74→})();
    75→
    76→export const metadata: Metadata = {
    77→  metadataBase: new URL(siteConfig.baseUrl),
    78→  title: resolveLocale(siteConfig.title),
    79→  description: resolveLocale(siteConfig.description),
    80→  icons: {
    81→    icon: faviconMeta,
    82→  },
    83→  ...(feedAlternates && { alternates: feedAlternates }),
    84→  openGraph: {
    85→    siteName: resolveLocale(siteConfig.title),
    86→    locale: siteConfig.i18n.defaultLocale,
    87→    type: 'website',
    88→    images: [{ url: siteConfig.ogImage, width: 1200, height: 630 }],
    89→  },
    90→  twitter: {
    91→    card: 'summary',
    92→    site: siteTwitterHandle,
    93→    creator: siteTwitterHandle,
    94→  },
    95→};
    96→
    97→export default function RootLayout({
    98→  children,
    99→}: Readonly<{
   100→  children: React.ReactNode;
   101→}>) {
   102→  const features = siteConfig.features;
   103→
   104→  // Build series list for navbar (only when series feature is enabled)
   105→  const seriesNavItem = siteConfig.nav.find(item => item.url === '/series');
   106→  const featuredSeries = seriesNavItem?.dropdown;
   107→  let seriesList: { name: string; slug: string }[] = [];
   108→  if (features?.series?.enabled !== false) {
   109→    const allSeries = getAllSeries();
   110→    const seriesKeys = Object.keys(allSeries).sort();
   111→    const filteredKeys = featuredSeries && featuredSeries.length > 0
   112→      ? seriesKeys.filter(slug => featuredSeries.includes(slug))
   113→      : [];
   114→    seriesList = filteredKeys.map(slug => ({
   115→      name: getSeriesData(slug)?.title || allSeries[slug][0]?.series || slug,
   116→      slug,
   117→    }));
   118→  }
   119→
   120→  // Build books list for navbar (only when books feature is enabled)
   121→  const booksNavItem = siteConfig.nav.find(item => item.url === '/books');
   122→  const featuredBookSlugs = booksNavItem?.dropdown;
   123→  let booksList: { name: string; slug: string }[] = [];
   124→  if (features?.books?.enabled !== false) {
   125→    const allBooks = getAllBooks();
   126→    booksList = featuredBookSlugs && featuredBookSlugs.length > 0
   127→      ? allBooks
   128→          .filter(book => featuredBookSlugs.includes(book.slug))
   129→          .map(book => ({ name: book.title, slug: book.slug }))
   130→      : [];
   131→  }
   132→
   133→  return (
   134→    <html lang={siteConfig.i18n.defaultLocale} data-scroll-behavior="smooth" suppressHydrationWarning>
   135→      <body
   136→        className={`${inter.variable} ${baskerville.variable} font-sans min-h-screen transition-colors duration-300`}
   137→        data-palette={siteConfig.themeColor}
   138→        suppressHydrationWarning
   139→      >
   140→        {/* Skip to main content link for accessibility */}
   141→        <a
   142→          href="#main-content"
   143→          className="sr-only focus:not-sr-only focus:absolute focus:top-4 focus:left-4 focus:z-[100] focus:px-4 focus:py-2 focus:bg-accent focus:text-white focus:rounded-lg focus:outline-none focus:ring-2 focus:ring-accent focus:ring-offset-2"
   144→        >
   145→          Skip to main content
   146→        </a>
   147→        <ThemeProvider>
   148→          <LanguageProvider>
   149→            <div className="selection:bg-accent/20 selection:text-accent dark:selection:bg-accent/30 dark:selection:text-accent min-h-screen flex flex-col">
   150→              <Navbar seriesList={seriesList} booksList={booksList} />
   151→              <main id="main-content" className="pt-16 flex-grow">
   152→                <BrowserDetectionBanner updateUrl={siteConfig.browserCheck?.updateUrl} />
   153→                {children}
   154→              </main>
   155→              <Footer />
   156→            </div>
   157→            <Analytics />
   158→          </LanguageProvider>
   159→        </ThemeProvider>
   160→      </body>
   161→    </html>
   162→  );
   163→}

