import { getBookData, getAllBooks, getAuthorSlug } from '@/lib/markdown';
import { notFound } from 'next/navigation';
import { Metadata } from 'next';
import { siteConfig } from '../../../../site.config';
import CoverImage from '@/components/CoverImage';
import MarkdownRenderer from '@/components/MarkdownRenderer';
import Link from 'next/link';
import { t, resolveLocale } from '@/lib/i18n';
import { buildBookJsonLd, serializeJsonLd } from '@/lib/json-ld';
import { getBookUrl } from '@/lib/urls';

export async function generateStaticParams() {
  const books = getAllBooks();
  if (books.length === 0) return [{ slug: '_' }];
  return books.map(book => ({ slug: book.slug }));
}

export const dynamicParams = false;

export async function generateMetadata({ params }: { params: Promise<{ slug: string }> }): Promise<Metadata> {
  const { slug } = await params;
  const book = getBookData(decodeURIComponent(slug));

  if (!book) {
    return { title: 'Book Not Found' };
  }

  const ogImage = book.coverImage && !book.coverImage.startsWith('text:') && !book.coverImage.startsWith('./')
    ? book.coverImage
    : siteConfig.ogImage;

  return {
    title: `${book.title} | ${resolveLocale(siteConfig.title)}`,
    description: book.excerpt,
    openGraph: {
      title: book.title,
      description: book.excerpt,
      type: 'website',
      url: `${siteConfig.baseUrl}/books/${slug}`,
      siteName: resolveLocale(siteConfig.title),
      images: [{ url: ogImage, width: 1200, height: 630, alt: book.title }],
    },
    twitter: {
      card: ogImage !== siteConfig.ogImage ? 'summary_large_image' : 'summary',
      title: book.title,
      description: book.excerpt,
      images: [ogImage],
    },
  };
}

export default async function BookLandingPage({ params }: { params: Promise<{ slug: string }> }) {
  const { slug: rawSlug } = await params;
  const slug = decodeURIComponent(rawSlug);
  const book = getBookData(slug);

  if (!book || (process.env.NODE_ENV === 'production' && book.draft)) {
    notFound();
  }

import type { NextConfig } from "next";

const nextConfig: NextConfig = {
  /* config options here */
  reactCompiler: true,
  // Next.js default is false (slug.html), but we use true (slug/index.html)
  // for two reasons:
  //   1. Co-located assets: posts can have a slug/images/ directory alongside
  //      slug/index.html. With false, slug.html and slug/ conflict on some
  //      static hosts and cause 403 errors.
  //   2. Nginx cosmetics: nginx.conf strips the trailing slash via redirect
  //      (/slug/ → /slug) so the visible URL matches the false convention
  //      without changing the export format.
  trailingSlash: true,
  output: "export",
  images: {
    loader: "custom",
    imageSizes: [16, 32, 48, 64, 96, 128, 256, 384],
    deviceSizes: [640, 750, 828, 1080, 1200, 1920, 2048, 3840],
  },
  transpilePackages: ["next-image-export-optimizer"],
  env: {
    nextImageExportOptimizer_imageFolderPath: "public",
    nextImageExportOptimizer_exportFolderPath: "out",
    nextImageExportOptimizer_quality: "75",
    nextImageExportOptimizer_storePicturesInWEBP: "true",
    nextImageExportOptimizer_generateAndUseBlurImages: "true",
  },
};

export default nextConfig;

